// 1. Base de datos simulada y firma secreta
const SECRET_KEY = "fUSoftSecureKey2026";
const dbUsers = [
  { id: 1, name: "Camilo Perez", email: "camilo@uni.edu.co", password: "pass123", role: "ESTUDIANTE" },
