];

// 2. Función simuladora de JWT
function generateSimulatedToken(payload) {
  const header = btoa(JSON.stringify({ alg: "HS256", typ: "JWT" }));
  const data = btoa(JSON.stringify({ ...payload, exp: Date.now() + 36000 }));
  return `${header}.${data}.${btoa(SECRET_KEY)}`;
}

function verifySimulatedToken(token) {
  try {
    const parts = token.split('.');
    const data = JSON.parse(atob(parts[1]));
    const signature = atob(parts[2]);
    if (signature !== SECRET_KEY) throw new Error();
    return data;
  } catch (e) {
    return null;
  }
}

// 3. Router de Endpoints simulado
function handleRequest(method, path, body, headers = {}) {
  console.log(`\n[HTTP REQUEST]: ${method} ${path}`);

  if (method === "POST" && path === "/api/login") {
    const user = dbUsers.find(u => u.email === body.email && u.password === body.password);
    if (!user) return { status: 401, json: { error: "Credenciales incorrectas" } };

    const token = generateSimulatedToken({ id: user.id, name: user.name, role: user.role });
    return { status: 200, json: { message: "Autenticación exitosa", token } };
  }

  if (method === "GET" && path === "/api/students") {
    const authHeader = headers["Authorization"];
    const token = authHeader && authHeader.split(' ')[1];
    const user = verifySimulatedToken(token || "");

    if (!user) return { status: 401, json: { error: "Token ausente o inválido" } };
    if (user.role !== "PROFESOR" && user.role !== "ADMIN") {
      return { status: 403, json: { error: "Acceso denegado: Se requiere rol de Profesor o Admin" } };
    }

    return { status: 200, json: { students: dbUsers.filter(u => u.role === "ESTUDIANTE") } };
  }

  return { status: 404, json: { error: "Ruta no encontrada" } };
}

