// Implementación interactiva en vivo del Árbol de Búsqueda Binaria (BST)

class TreeNode {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

class BinarySearchTree {
  constructor() {
    this.root = null;
  }

  insert(key, value) {
    const node = new TreeNode(key, value);
    if (!this.root) {
      this.root = node;
      console.log(`[BST] Raíz creada con éxito: [${key}] - ${value}`);
    } else {
      this.insertNode(this.root, node);
    }
  }

  insertNode(node, newNode) {
    if (newNode.key < node.key) {
      if (!node.left) {
        node.left = newNode;
        console.log(`[BST] Nodo [${newNode.key}] - ${newNode.value} insertado a la IZQUIERDA de [${node.key}]`);
      } else {
        this.insertNode(node.left, newNode);
      }
    } else {
      if (!node.right) {
        node.right = newNode;
        console.log(`[BST] Nodo [${newNode.key}] - ${newNode.value} insertado a la DERECHA de [${node.key}]`);
      } else {
        this.insertNode(node.right, newNode);
      }
    }
  }

  inOrder(node, results = []) {
    if (node) {
      this.inOrder(node.left, results);
      results.push(`${node.key}: ${node.value}`);
      this.inOrder(node.right, results);
    }
    return results;
  }
}

