// 2. Servidor Remoto Simulado (Con opción de apagar conexión)
let isNetworkOnline = true;

// 3. Simulador de Intercepción Fetch de Service Worker
function serviceWorkerInterceptFetch(requestUrl) {
  console.log(`\n[SW Proxy] Interceptando fetch para: [${requestUrl}]`);

  if (isNetworkOnline) {
    console.log(`[SW Proxy] Conexión activa. Obteniendo de la red real...`);
    return {
      source: "NETWORK",
      status: 200,
      data: `Petición exitosa para ${requestUrl} (servidor en vivo)`
    };
  } else {
    console.log(`[SW Proxy] ¡Sin conexión! Buscando fallback en Cache Storage...`);
    const cacheVersion = "v2.1-stable";
    const cachedResponse = simulatedCache[cacheVersion][requestUrl];

    if (cachedResponse) {
      console.log(`[SW Proxy] ✅ Encontrado en caché (${cacheVersion})`);
      return {
        source: "CACHE",
        status: 200,
        data: cachedResponse
      };
    } else {
      console.log(`[SW Proxy] ❌ No encontrado en caché. Retornando página de error offline.`);
      return {
        source: "OFFLINE_FALLBACK",
        status: 503,
        data: "Lo sentimos, este recurso no está guardado en el caché para uso offline."
      };
    }
  }
}

