// Simulacion simplificada de cache de QueryClient y Fetching
class QueryClient {
  constructor() {
    this.cache = {};
  }

  async fetchQuery(queryKey, queryFn, options = { staleTime: 2000 }) {
    const cached = this.cache[queryKey];
    const now = Date.now();

    if (cached && (now - cached.timestamp < options.staleTime)) {
      console.log(`[QueryClient]: Datos en CACHE para [${queryKey}]. Retornando datos instantaneamente.`);
      return cached.data;
    }

    console.log(`[QueryClient]: Datos EXPIRADOS o INEXISTENTES para [${queryKey}]. Fetching de red...`);
    const data = await queryFn();
    this.cache[queryKey] = {
      data,
      timestamp: now
    };
    return data;
  }
}

