// Implementacion interactiva de Arbol Trie para Autocompletado en vivo
class TrieNode {
  constructor() {
    this.children = {};
    this.isEndOfWord = false;
  }
}

class Trie {
  constructor() {
    this.root = new TrieNode();
  }

  insert(word) {
    let current = this.root;
    for (let char of word) {
      if (!current.children[char]) {
        current.children[char] = new TrieNode();
      }
      current = current.children[char];
    }
    current.isEndOfWord = true;
    console.log(`[Trie]: Palabra "${word}" insertada en el arbol de prefijos.`);
  }

  searchSuggest(prefix) {
    let current = this.root;
    for (let char of prefix) {
      if (!current.children[char]) {
        return []; // Sin sugerencias
      }
      current = current.children[char];
    }

    const results = [];
    this.collectWords(current, prefix, results);
    return results;
  }

  collectWords(node, prefix, results) {
    if (node.isEndOfWord) {
      results.push(prefix);
    }
    for (let char in node.children) {
      this.collectWords(node.children[char], prefix + char, results);
    }
  }
}

