// Simulacion de Middleware de Rate Limiter y Sanitizacion
const reqHistory = {};

function rateLimiterMiddleware(ip) {
  const now = Date.now();
  const limitWindow = 1000; // 1 segundo
  const maxRequests = 2;

  if (!reqHistory[ip]) {
    reqHistory[ip] = [];
  }

  // Filtrar peticiones viejas
  reqHistory[ip] = reqHistory[ip].filter(t => now - t < limitWindow);

  if (reqHistory[ip].length >= maxRequests) {
    console.log(`[Rate Limiter] ❌ Bloqueado! IP: ${ip} superó el límite de peticiones.`);
    return false; // Denegado
  }

  reqHistory[ip].push(now);
  console.log(`[Rate Limiter] ✅ Permetido. IP: ${ip} - Solicitudes activas: ${reqHistory[ip].length}`);
  return true;
}

