// Implementacion interactiva del Algoritmo Dijkstra en Grafos
class Graph {
  constructor() {
    this.adjacencyList = {};
  }

  addVertex(vertex) {
    if (!this.adjacencyList[vertex]) this.adjacencyList[vertex] = [];
  }

  addEdge(v1, v2, weight) {
    this.adjacencyList[v1].push({ node: v2, weight });
    this.adjacencyList[v2].push({ node: v1, weight });
  }

  dijkstra(start, finish) {
    const distances = {};
    const previous = {};
    let path = []; // Camino final
    let smallest;

    // Inicializacion del grafo
    for (let vertex in this.adjacencyList) {
      if (vertex === start) {
        distances[vertex] = 0;
      } else {
        distances[vertex] = Infinity;
      }
      previous[vertex] = null;
    }

    // Simulacion simplificada de cola de prioridad (tomando nodos no visitados)
    const unvisited = Object.keys(this.adjacencyList);

    while (unvisited.length) {
      unvisited.sort((a, b) => distances[a] - distances[b]);
      smallest = unvisited.shift();

      if (smallest === finish) {
        // Construir camino
        while (previous[smallest]) {
          path.push(smallest);
          smallest = previous[smallest];
        }
        break;
      }

      if (distances[smallest] === Infinity) break;

      for (let neighbor of this.adjacencyList[smallest]) {
        let candidate = distances[smallest] + neighbor.weight;
        if (candidate < distances[neighbor.node]) {
          distances[neighbor.node] = candidate;
          previous[neighbor.node] = smallest;
        }
      }
    }

    return [start, ...path.reverse()];
  }
}

