// Implementacion simplificada de Arbol AVL (Rotaciones Izquierda y Derecha)
class AVLNode {
  constructor(val) {
    this.val = val;
    this.left = null;
    this.right = null;
    this.height = 1;
  }
}

class AVLTree {
  getHeight(node) {
    return node ? node.height : 0;
  }

  getBalanceFactor(node) {
    return node ? this.getHeight(node.left) - this.getHeight(node.right) : 0;
  }

  rightRotate(y) {
    console.log(`[AVL Rotación]: Girando a la derecha sobre nodo ${y.val}`);
    const x = y.left;
    const T2 = x.right;

    x.right = y;
    y.left = T2;

    y.height = Math.max(this.getHeight(y.left), this.getHeight(y.right)) + 1;
    x.height = Math.max(this.getHeight(x.left), this.getHeight(x.right)) + 1;

    return x;
  }

  leftRotate(x) {
    console.log(`[AVL Rotación]: Girando a la izquierda sobre nodo ${x.val}`);
    const y = x.right;
    const T2 = y.left;

    y.left = x;
    x.right = T2;

    x.height = Math.max(this.getHeight(x.left), this.getHeight(x.right)) + 1;
    y.height = Math.max(this.getHeight(y.left), this.getHeight(y.right)) + 1;

    return y;
  }

  insert(node, val) {
    if (!node) return new AVLNode(val);

    if (val < node.val) {
      node.left = this.insert(node.left, val);
    } else if (val > node.val) {
      node.right = this.insert(node.right, val);
    } else {
      return node; // No duplicados
    }

    node.height = Math.max(this.getHeight(node.left), this.getHeight(node.right)) + 1;
    const balance = this.getBalanceFactor(node);

    // Caso Izquierda Izquierda (LL)
    if (balance > 1 && val < node.left.val) {
      return this.rightRotate(node);
    }
    // Caso Derecha Derecha (RR)
    if (balance < -1 && val > node.right.val) {
      return this.leftRotate(node);
    }

    return node;
  }
}

