class ReplicaSetController {
  constructor(desiredReplicas) {
    this.desired = desiredReplicas;
    this.pods = [];
  }

  reconcile() {
    console.log(`\n--- K8s Reconciliation Loop (Deseadas: ${this.desired}) ---`);

    // Si faltan pods
    while (this.pods.length < this.desired) {
      const id = Math.floor(Math.random() * 1000);
      const newPod = new Pod(`fusoft-api-pod-${id}`);
      this.pods.push(newPod);
      console.log(`[K8s Controller]: 🟢 Creando Pod nuevo: ${newPod.name} para cumplir requerimiento.`);
    }

    // Si sobran pods
    while (this.pods.length > this.desired) {
      const removed = this.pods.pop();
      console.log(`[K8s Controller]: 🔴 Eliminando Pod sobrante: ${removed.name}.`);
    }

    console.log(`Estado del clúster: ${this.pods.length} pods activos y estables.`);
  }

  scale(newSize) {
    console.log(`\n[HPA AutoScaler]: Ajustando réplicas de ${this.desired} a ${newSize} debido a alto tráfico.`);
    this.desired = newSize;
    this.reconcile();
  }
}

