// Resolucion del problema de la Mochila 0-1 mediante Programacion Dinamica
function knapsack(values, weights, capacity) {
  const n = values.length;
  // Inicialización de matriz de memorización
  const dp = Array.from({ length: n + 1 }, () => Array(capacity + 1).fill(0));

  for (let i = 1; i <= n; i++) {
    for (let w = 1; w <= capacity; w++) {
      if (weights[i - 1] <= w) {
        dp[i][w] = Math.max(
          values[i - 1] + dp[i - 1][w - weights[i - 1]],
          dp[i - 1][w]
        );
      } else {
        dp[i][w] = dp[i - 1][w];
      }
    }
  }

  console.log("Matriz de resolucion memorizada final calculada (valores maximos por celda):");
  console.log(dp.map(row => row.join(" | ")).join("\n"));

  return dp[n][capacity];
}

