// Compilador y Maquina Virtual de Pila Didactica
class StackVM {
  constructor() {
    this.stack = [];
    this.instructions = [];
  }

  load(code) {
    this.instructions = code.trim().split("\n").map(line => line.trim().split(" "));
  }

  run() {
    console.log("--- Iniciando ejecucion de programa en Stack VM ---");
    for (let i = 0; i < this.instructions.length; i++) {
      const [op, val] = this.instructions[i];
      console.log(`\n[VM Inst]: ${op} ${val || ""}`);

      switch (op.toUpperCase()) {
        case "PUSH":
          this.stack.push(Number(val));
          break;
        case "POP":
          this.stack.pop();
          break;
        case "ADD": {
          const a = this.stack.pop();
          const b = this.stack.pop();
          this.stack.push(a + b);
          break;
        }
        case "SUB": {
          const a = this.stack.pop();
          const b = this.stack.pop();
          this.stack.push(b - a);
          break;
        }
        default:
          console.log("Error: Operación no soportada.");
      }
      console.log("Estado de la pila:", this.stack);
    }
  }
}

